pub fn create_branch(&self, branch_name: &str) -> Result<()> {
        if !self.is_git_repo() {
            warn!("Not a git repo, skipping branch creation for {branch_name}");
            return Ok(());
        }
        run_git(&self.data_dir, &["branch", branch_name])?;
        info!(branch_name, "git_branch_created");
        Ok(())
    }
